class Solution {
public:
    vector<int> shortestAlternatingPaths(int n, vector<vector<int>>& redEdges, vector<vector<int>>& blueEdges) {
        vector<int> result(n, -1);
        vector<vector<int>> graph[2];
        graph[0].resize(n);
        graph[1].resize(n);

        for (auto& edge : redEdges) {
            graph[0][edge[0]].push_back(edge[1]);
        }
        for (auto& edge : blueEdges) {
            graph[1][edge[0]].push_back(edge[1]);
        }

        queue<pair<int, int>> q;
        q.push({0, 0});
        q.push({0, 1});
        result[0] = 0;
        vector<vector<bool>> visited(2, vector<bool>(n));
        visited[0][0] = visited[1][0] = true;

        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; ++i) {
                auto [node, color] = q.front();
                q.pop();
                int nextColor = color ^ 1;
                for (int nextNode : graph[nextColor][node]) {
                    if (!visited[nextColor][nextNode]) {
                        visited[nextColor][nextNode] = true;
                        result[nextNode] = result[node] + 1;
                        q.push({nextNode, nextColor});
                    }
                }
            }
        }
        return result;
    }
};
